const scaleHorizontally = (line: string, scaleFactor: number): string =>
  line.split("").map((char) => char.repeat(scaleFactor)).join("");

const scaleVertically = (line: string, scaleFactor: number): string[] =>
  Array(scaleFactor).fill(line);

export function scale(image: string[], scaleFactor: number): string[] {
  if (scaleFactor === 1) {
    return [...image];
  }
  if (image.length === 0) {
    return [];
  }

  return image.map((line) => {
    if (line.length === 1) {
      return scaleVertically(line, scaleFactor);
    } else {
      return [scaleHorizontally(line, scaleFactor)];
    }
  }).flat();
}

Component Count:
- Constants: 2 (1, 0) = 2 × 1 = 2
- Bindings/Scalars: 5 (image, scaleFactor, line, char, line in helpers) = 5 × 1 = 5
- Invocations: 10 (split, map, repeat, join, Array, fill, scaleVertically, scaleHorizontally, map outer, flat) = 10 × 2 = 20
- Conditionals: 2 (if scaleFactor === 1, if line.length === 1) = 2 × 4 = 8
- Loops: 1 (map in scaleHorizontally, but counted above) = 1 × 5 = 5
- Assignments: 0 = 0

Total Mass: 2 + 5 + 20 + 8 + 5 + 0 = 40
```

